typedef struct {
    logic [2:0] counter;
    logic flag;
} SimpleStruct;
SimpleStruct s [1];
always @(posedge clock) begin
    s[0].counter <= s[0].counter + 3'd1;
    s[0].flag <= 0;
end

typedef struct {
    logic [2:0] counter;
    logic flag;
} SimpleStruct;
SimpleStruct s [1];
always @(posedge clock) begin
    for (int i = 0; i < 1; i++) begin
        s[i].counter <= s[i].counter + 3'd1;
        s[i].flag <= 0;
    end
end
